contracts/FileRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title FileRegistry
/// @notice Records file ownership, chunk distribution maps, and integrity hashes.
/// @dev When a user uploads a file, this contract stores the "map" of where each
///      encrypted chunk lives and who owns the file. No actual file data is stored here —
///      only the metadata needed to prove ownership and locate chunks.
contract FileRegistry {

    // ─────────────────────────────────────────────
    //  DATA STRUCTURES
    // ─────────────────────────────────────────────

    struct FileRecord {
        bytes32   fileId;            // Unique identifier for this file (keccak256 hash)
        address   owner;             // The renter's wallet address (only they can retrieve)
        uint256   sizeBytes;         // Original file size in bytes
        uint8     totalChunks;       // Total number of pieces (data + parity)
        uint8     dataChunks;        // k in Reed-Solomon(k, m) — minimum chunks to reconstruct
        bytes32[] chunkHashes;       // SHA-256 hash of each encrypted chunk (integrity check)
        address[] hostAssignments;   // Which host wallet stores which chunk (index = chunk number)
        string    fileName;          // Original file name (for display only)
        uint256   uploadedAt;        // Block timestamp of upload
        bool      isDeleted;         // Soft delete flag (true = file has been removed)
        bytes     encryptedKeyData;  // Master encryption key, asymmetrically encrypted with owner's key
    }

    // ─────────────────────────────────────────────
    //  STATE VARIABLES
    // ─────────────────────────────────────────────

    address public owner;                              // Platform admin
    uint256 public totalFiles;                         // Total files ever uploaded

    mapping(bytes32 => FileRecord) public fileRecords; // fileId → FileRecord
    mapping(address => bytes32[]) public userFiles;    // user wallet → list of their fileIds

    // ─────────────────────────────────────────────
    //  EVENTS
    // ─────────────────────────────────────────────

    event FileUploaded(
        bytes32 indexed fileId,
        address indexed owner,
        string  fileName,
        uint256 sizeBytes,
        uint256 totalChunks
    );
    event FileDeleted(bytes32 indexed fileId, address indexed owner);
    event ChunkReassigned(bytes32 indexed fileId, uint8 chunkIndex, address newHost);

    // ─────────────────────────────────────────────
    //  MODIFIERS
    // ─────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "Only platform admin");
        _;
    }

    modifier onlyFileOwner(bytes32 _fileId) {
        require(
            fileRecords[_fileId].owner == msg.sender,
            "Only the file owner can perform this action"
        );
        _;
    }

    modifier fileExists(bytes32 _fileId) {
        require(fileRecords[_fileId].owner != address(0), "File not found");
        require(!fileRecords[_fileId].isDeleted, "File has been deleted");
        _;
    }

    // ─────────────────────────────────────────────
    //  CONSTRUCTOR
    // ─────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
    }

    // ─────────────────────────────────────────────
    //  CORE FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Register a newly uploaded file's metadata on the blockchain
    /// @dev Called by the frontend AFTER chunks have been distributed to hosts
    /// @param _fileId Unique ID for the file (generated client-side as keccak256 of file content)
    /// @param _fileName Original file name
    /// @param _sizeBytes File size in bytes
    /// @param _dataChunks k value — minimum chunks needed to reconstruct (e.g., 10)
    /// @param _chunkHashes Array of SHA-256 hashes for each chunk (for integrity verification)
    /// @param _hostAssignments Array of host wallet addresses — index matches chunk number
    /// @param _encryptedKeyData The master AES key, encrypted with the owner's public key
    function uploadFileMap(
        bytes32          _fileId,
        string    memory _fileName,
        uint256          _sizeBytes,
        uint8            _dataChunks,
        bytes32[] memory _chunkHashes,
        address[] memory _hostAssignments,
        bytes     memory _encryptedKeyData
    ) external {
        require(fileRecords[_fileId].owner == address(0), "File ID already exists");
        require(_chunkHashes.length == _hostAssignments.length, "Chunk hashes and host assignments must match");
        require(_chunkHashes.length > 0, "Must have at least one chunk");
        require(_sizeBytes > 0, "File size must be greater than 0");
        require(_dataChunks > 0 && _dataChunks <= _chunkHashes.length, "Invalid data chunk count");

        fileRecords[_fileId] = FileRecord({
            fileId:           _fileId,
            owner:            msg.sender,
            sizeBytes:        _sizeBytes,
            totalChunks:      uint8(_chunkHashes.length),
            dataChunks:       _dataChunks,
            chunkHashes:      _chunkHashes,
            hostAssignments:  _hostAssignments,
            fileName:         _fileName,
            uploadedAt:       block.timestamp,
            isDeleted:        false,
            encryptedKeyData: _encryptedKeyData
        });

        userFiles[msg.sender].push(_fileId);
        totalFiles++;

        emit FileUploaded(_fileId, msg.sender, _fileName, _sizeBytes, _chunkHashes.length);
    }

    /// @notice Delete a file (soft delete — metadata stays for audit trail)
    /// @param _fileId The ID of the file to delete
    function deleteFile(bytes32 _fileId)
        external
        fileExists(_fileId)
        onlyFileOwner(_fileId)
    {
        fileRecords[_fileId].isDeleted = true;
        emit FileDeleted(_fileId, msg.sender);
    }

    /// @notice Reassign a chunk to a new host (called during re-replication)
    /// @dev Only platform admin can call this (triggered by HeartbeatMonitor)
    /// @param _fileId File whose chunk needs reassignment
    /// @param _chunkIndex Which chunk index to reassign
    /// @param _newHost Address of the new host that now holds this chunk
    function reassignChunk(
        bytes32 _fileId,
        uint8   _chunkIndex,
        address _newHost
    ) external onlyOwner fileExists(_fileId) {
        require(
            _chunkIndex < fileRecords[_fileId].totalChunks,
            "Invalid chunk index"
        );
        fileRecords[_fileId].hostAssignments[_chunkIndex] = _newHost;
        emit ChunkReassigned(_fileId, _chunkIndex, _newHost);
    }

    // ─────────────────────────────────────────────
    //  VIEW FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Get full file metadata
    function getFile(bytes32 _fileId)
        external
        view
        fileExists(_fileId)
        returns (FileRecord memory)
    {
        return fileRecords[_fileId];
    }

    /// @notice Get all file IDs belonging to a user
    function getUserFiles(address _userWallet)
        external
        view
        returns (bytes32[] memory)
    {
        return userFiles[_userWallet];
    }

    /// @notice Get the host assignments for a specific file (where each chunk lives)
    function getChunkLocations(bytes32 _fileId)
        external
        view
        fileExists(_fileId)
        returns (address[] memory)
    {
        return fileRecords[_fileId].hostAssignments;
    }

    /// @notice Get the chunk hashes for integrity verification
    function getChunkHashes(bytes32 _fileId)
        external
        view
        fileExists(_fileId)
        returns (bytes32[] memory)
    {
        return fileRecords[_fileId].chunkHashes;
    }

    /// @notice Verify that the caller is the file owner
    function verifyOwnership(bytes32 _fileId, address _claimant)
        external
        view
        returns (bool)
    {
        return fileRecords[_fileId].owner == _claimant && !fileRecords[_fileId].isDeleted;
    }
}

contracts/HeartbeatMonitor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title HeartbeatMonitor
/// @notice Tracks host liveness, verifies chunk integrity proofs, and triggers re-replication.
/// @dev Every active host must "ping" this contract every hour to prove they are online.
///      If they miss 3 pings → marked OFFLINE → chunks are re-replicated → deposit slashed.
contract HeartbeatMonitor {

    // ─────────────────────────────────────────────
    //  DATA STRUCTURES
    // ─────────────────────────────────────────────

    struct HeartbeatRecord {
        address hostWallet;         // Host's wallet address
        uint256 lastHeartbeatTime;  // Timestamp of their most recent ping
        uint256 missedHeartbeats;   // Consecutive missed heartbeats counter
        bytes32 lastMerkleRoot;     // Merkle root of all stored chunk hashes (integrity proof)
        bool    isOnline;           // Current online status
        uint256 totalHeartbeats;    // Lifetime heartbeat count (for reputation calculation)
        uint256 uptimeStart;        // When the current online streak started
    }

    // ─────────────────────────────────────────────
    //  STATE VARIABLES
    // ─────────────────────────────────────────────

    address public owner;

    uint256 public heartbeatInterval = 3600;    // Expected heartbeat every 3600 seconds (1 hour)
    uint256 public maxMissedHeartbeats = 3;     // Miss 3 → declared OFFLINE
    uint256 public slashAmountPerMiss = 0.001 ether; // Penalty per missed heartbeat

    mapping(address => HeartbeatRecord) public heartbeatRecords;
    address[] public monitoredHosts;

    // ─────────────────────────────────────────────
    //  EVENTS
    // ─────────────────────────────────────────────

    event HeartbeatReceived(
        address indexed host,
        uint256 timestamp,
        bytes32 merkleRoot
    );
    event HostDeclaredOffline(
        address indexed host,
        uint256 missedCount,
        uint256 timestamp
    );
    event ReplicationRequired(
        address indexed offlineHost,
        uint256 timestamp
    );
    event HostRejoined(address indexed host, uint256 timestamp);

    // ─────────────────────────────────────────────
    //  MODIFIERS
    // ─────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "Only platform admin");
        _;
    }

    // ─────────────────────────────────────────────
    //  CONSTRUCTOR
    // ─────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
    }

    // ─────────────────────────────────────────────
    //  CORE FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Register a host for heartbeat monitoring
    /// @dev Called automatically when a host registers in HostRegistry
    /// @param _hostWallet The wallet address of the host to monitor
    function startMonitoring(address _hostWallet) external onlyOwner {
        require(
            heartbeatRecords[_hostWallet].hostWallet == address(0),
            "Host already being monitored"
        );
        heartbeatRecords[_hostWallet] = HeartbeatRecord({
            hostWallet:        _hostWallet,
            lastHeartbeatTime: block.timestamp,
            missedHeartbeats:  0,
            lastMerkleRoot:    bytes32(0),
            isOnline:          true,
            totalHeartbeats:   0,
            uptimeStart:       block.timestamp
        });
        monitoredHosts.push(_hostWallet);
    }

    /// @notice Host submits a heartbeat to prove they are online and data is intact
    /// @param _merkleRoot The Merkle root computed over all stored chunk hashes
    ///        This proves the host still has all the data they were assigned
    function submitHeartbeat(bytes32 _merkleRoot) external {
        HeartbeatRecord storage record = heartbeatRecords[msg.sender];
        require(record.hostWallet != address(0), "Host not registered for monitoring");

        record.lastHeartbeatTime = block.timestamp;
        record.missedHeartbeats  = 0;          // Reset missed counter on successful ping
        record.lastMerkleRoot    = _merkleRoot;
        record.isOnline          = true;
        record.totalHeartbeats++;

        emit HeartbeatReceived(msg.sender, block.timestamp, _merkleRoot);
    }

    /// @notice Check a host and penalize them if they've missed too many heartbeats
    /// @dev This is called by the platform's monitoring service periodically
    /// @param _hostWallet Address of the host to check
    function checkHost(address _hostWallet) external onlyOwner {
        HeartbeatRecord storage record = heartbeatRecords[_hostWallet];
        require(record.hostWallet != address(0), "Host not monitored");

        // Check if they missed a heartbeat window
        bool missedWindow = (block.timestamp - record.lastHeartbeatTime) > heartbeatInterval;

        if (missedWindow && record.isOnline) {
            record.missedHeartbeats++;

            // If they've missed too many → declare OFFLINE
            if (record.missedHeartbeats >= maxMissedHeartbeats) {
                record.isOnline = false;
                emit HostDeclaredOffline(_hostWallet, record.missedHeartbeats, block.timestamp);
                emit ReplicationRequired(_hostWallet, block.timestamp);
            }
        }
    }

    /// @notice Host comes back online after being offline
    /// @param _merkleRoot Fresh Merkle root proving they have restored their data
    function rejoinNetwork(bytes32 _merkleRoot) external {
        HeartbeatRecord storage record = heartbeatRecords[msg.sender];
        require(record.hostWallet != address(0), "Not registered");
        require(!record.isOnline, "Already online");

        record.isOnline          = true;
        record.missedHeartbeats  = 0;
        record.lastHeartbeatTime = block.timestamp;
        record.lastMerkleRoot    = _merkleRoot;
        record.uptimeStart       = block.timestamp;

        emit HostRejoined(msg.sender, block.timestamp);
    }

    // ─────────────────────────────────────────────
    //  VIEW FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Check if a host is currently online
    function isHostOnline(address _hostWallet) external view returns (bool) {
        HeartbeatRecord storage record = heartbeatRecords[_hostWallet];
        if (record.hostWallet == address(0)) return false;
        // Also check they haven't timed out since last heartbeat
        bool timedOut = (block.timestamp - record.lastHeartbeatTime) > (heartbeatInterval * maxMissedHeartbeats);
        return record.isOnline && !timedOut;
    }

    /// @notice Get full heartbeat record for a host
    function getHeartbeatRecord(address _hostWallet)
        external
        view
        returns (HeartbeatRecord memory)
    {
        return heartbeatRecords[_hostWallet];
    }

    /// @notice Get how many seconds since a host's last heartbeat
    function getTimeSinceLastHeartbeat(address _hostWallet)
        external
        view
        returns (uint256)
    {
        return block.timestamp - heartbeatRecords[_hostWallet].lastHeartbeatTime;
    }

    /// @notice Calculate the uptime percentage of a host (0–100)
    function getUptimePercentage(address _hostWallet)
        external
        view
        returns (uint256)
    {
        HeartbeatRecord storage record = heartbeatRecords[_hostWallet];
        if (record.hostWallet == address(0)) return 0;

        uint256 totalTimeMonitored = block.timestamp - record.uptimeStart;
        if (totalTimeMonitored == 0) return 100;

        uint256 expectedHeartbeats = totalTimeMonitored / heartbeatInterval;
        if (expectedHeartbeats == 0) return 100;

        uint256 actualHeartbeats = record.totalHeartbeats;
        if (actualHeartbeats >= expectedHeartbeats) return 100;

        return (actualHeartbeats * 100) / expectedHeartbeats;
    }

    /// @notice Get all currently offline hosts
    function getOfflineHosts() external view returns (address[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < monitoredHosts.length; i++) {
            if (!heartbeatRecords[monitoredHosts[i]].isOnline) {
                count++;
            }
        }
        address[] memory offlineHosts = new address[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < monitoredHosts.length; i++) {
            if (!heartbeatRecords[monitoredHosts[i]].isOnline) {
                offlineHosts[idx] = monitoredHosts[i];
                idx++;
            }
        }
        return offlineHosts;
    }
}

contracts/HostRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title HostRegistry
/// @notice Manages storage host registration, space declarations, and security deposits.
/// @dev Every device owner who wants to rent out disk space registers here.
contract HostRegistry {

    // ─────────────────────────────────────────────
    //  DATA STRUCTURES
    // ─────────────────────────────────────────────

    struct Host {
        address wallet;             // Ethereum wallet address (unique identity)
        uint256 totalSpaceGB;       // Total space declared for sharing (in GB)
        uint256 availableSpaceGB;   // Space currently not yet allocated
        uint256 pricePerGBPerDay;   // Price in smallest unit (e.g., paise / cents)
        string  country;            // ISO country code e.g. "IN", "US", "DE"
        bytes32 paymentAccountHash; // keccak256 hash of their UPI/bank details (private)
        uint256 depositAmount;      // Security deposit locked in this contract (in wei)
        bool    isActive;           // Is the host currently online and serving?
        uint256 reputationScore;    // 0–100 score based on uptime history
        uint256 joinedAt;           // Block timestamp when they registered
        uint256 totalEarned;        // Lifetime earnings tracked (in smallest currency unit)
    }

    // ─────────────────────────────────────────────
    //  STATE VARIABLES
    // ─────────────────────────────────────────────

    address public owner;                          // Contract deployer (platform admin)
    uint256 public minimumDeposit = 0.01 ether;    // Minimum deposit to become a host
    uint256 public totalHosts;                     // Total number of registered hosts

    mapping(address => Host) public hosts;         // wallet address → Host struct
    address[] public hostList;                     // Array of all host addresses (for iteration)

    // ─────────────────────────────────────────────
    //  EVENTS  (blockchain logs — like notifications)
    // ─────────────────────────────────────────────

    event HostRegistered(address indexed wallet, uint256 spaceGB, string country);
    event HostDeregistered(address indexed wallet);
    event SpaceUpdated(address indexed wallet, uint256 newAvailableSpaceGB);
    event DepositSlashed(address indexed wallet, uint256 amount, string reason);
    event ReputationUpdated(address indexed wallet, uint256 newScore);

    // ─────────────────────────────────────────────
    //  MODIFIERS  (reusable conditions)
    // ─────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "Only platform admin can call this");
        _;
    }

    modifier onlyRegisteredHost() {
        require(hosts[msg.sender].wallet != address(0), "You are not a registered host");
        _;
    }

    modifier onlyActiveHost() {
        require(hosts[msg.sender].isActive, "Host is not active");
        _;
    }

    // ─────────────────────────────────────────────
    //  CONSTRUCTOR
    // ─────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
    }

    // ─────────────────────────────────────────────
    //  CORE FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Register as a storage host on the DecentraStore network
    /// @param _spaceGB Amount of disk space (in GB) you want to share
    /// @param _pricePerGBPerDay Your asking price per GB per day (in smallest currency unit)
    /// @param _country Your ISO country code (e.g., "IN" for India)
    /// @param _paymentAccountHash keccak256 hash of your UPI ID or bank account
    function registerHost(
        uint256 _spaceGB,
        uint256 _pricePerGBPerDay,
        string  memory _country,
        bytes32 _paymentAccountHash
    ) external payable {
        // Validations
        require(hosts[msg.sender].wallet == address(0), "Already registered as a host");
        require(_spaceGB > 0, "Space must be greater than 0 GB");
        require(_pricePerGBPerDay > 0, "Price must be greater than 0");
        require(bytes(_country).length == 2, "Country must be a 2-letter ISO code");
        require(msg.value >= minimumDeposit, "Insufficient security deposit");

        // Create the host record
        hosts[msg.sender] = Host({
            wallet:              msg.sender,
            totalSpaceGB:        _spaceGB,
            availableSpaceGB:    _spaceGB,
            pricePerGBPerDay:    _pricePerGBPerDay,
            country:             _country,
            paymentAccountHash:  _paymentAccountHash,
            depositAmount:       msg.value,
            isActive:            true,
            reputationScore:     50,       // Start with neutral score
            joinedAt:            block.timestamp,
            totalEarned:         0
        });

        hostList.push(msg.sender);
        totalHosts++;

        emit HostRegistered(msg.sender, _spaceGB, _country);
    }

    /// @notice Update your available space (call this when space changes)
    /// @param _newAvailableSpaceGB Updated available space in GB
    function updateAvailableSpace(uint256 _newAvailableSpaceGB)
        external
        onlyRegisteredHost
    {
        require(
            _newAvailableSpaceGB <= hosts[msg.sender].totalSpaceGB,
            "Available space cannot exceed total declared space"
        );
        hosts[msg.sender].availableSpaceGB = _newAvailableSpaceGB;
        emit SpaceUpdated(msg.sender, _newAvailableSpaceGB);
    }

    /// @notice Set your active status (go online/offline)
    /// @param _status true = online, false = offline
    function setActiveStatus(bool _status) external onlyRegisteredHost {
        hosts[msg.sender].isActive = _status;
    }

    /// @notice Deregister and withdraw your deposit
    /// @dev Can only be called if host has no active file assignments (enforced off-chain)
    function deregisterHost() external onlyRegisteredHost {
        Host storage h = hosts[msg.sender];
        uint256 depositToReturn = h.depositAmount;

        h.isActive = false;
        h.depositAmount = 0;

        // Return deposit to host
        payable(msg.sender).transfer(depositToReturn);

        emit HostDeregistered(msg.sender);
    }

    /// @notice Slash (penalize) a host's deposit for bad behavior
    /// @dev Only callable by platform admin
    /// @param _hostWallet Address of the misbehaving host
    /// @param _amount Amount to slash in wei
    /// @param _reason Human-readable reason for the slash
    function slashDeposit(
        address _hostWallet,
        uint256 _amount,
        string memory _reason
    ) external onlyOwner {
        Host storage h = hosts[_hostWallet];
        require(h.wallet != address(0), "Host not found");
        require(h.depositAmount >= _amount, "Slash amount exceeds deposit");

        h.depositAmount -= _amount;
        // Slashed funds go to platform treasury (contract owner)
        payable(owner).transfer(_amount);

        // Reduce reputation score
        if (h.reputationScore >= 10) {
            h.reputationScore -= 10;
        } else {
            h.reputationScore = 0;
        }

        emit DepositSlashed(_hostWallet, _amount, _reason);
    }

    /// @notice Update a host's reputation score
    /// @dev Called by platform after evaluating heartbeat history
    function updateReputation(address _hostWallet, uint256 _newScore)
        external
        onlyOwner
    {
        require(_newScore <= 100, "Score must be between 0 and 100");
        hosts[_hostWallet].reputationScore = _newScore;
        emit ReputationUpdated(_hostWallet, _newScore);
    }

    // ─────────────────────────────────────────────
    //  VIEW FUNCTIONS (read-only, free to call)
    // ─────────────────────────────────────────────

    /// @notice Get details of a specific host
    function getHost(address _wallet) external view returns (Host memory) {
        return hosts[_wallet];
    }

    /// @notice Get list of all active hosts with available space
    function getActiveHosts() external view returns (address[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < hostList.length; i++) {
            if (hosts[hostList[i]].isActive && hosts[hostList[i]].availableSpaceGB > 0) {
                count++;
            }
        }

        address[] memory activeHosts = new address[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < hostList.length; i++) {
            if (hosts[hostList[i]].isActive && hosts[hostList[i]].availableSpaceGB > 0) {
                activeHosts[idx] = hostList[i];
                idx++;
            }
        }
        return activeHosts;
    }

    /// @notice Check if an address is a registered active host
    function isActiveHost(address _wallet) external view returns (bool) {
        return hosts[_wallet].isActive && hosts[_wallet].wallet != address(0);
    }

    /// @notice Get total number of registered hosts
    function getTotalHosts() external view returns (uint256) {
        return totalHosts;
    }
}

contracts/PaymentLedger.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title PaymentLedger
/// @notice Tracks storage earnings for hosts and prepaid credits for renters.
/// @dev The blockchain is the LEDGER only. Actual fiat money (UPI/bank) is
///      transferred off-chain by the Razorpay API when this contract emits a PaymentDue event.
contract PaymentLedger {

    // ─────────────────────────────────────────────
    //  DATA STRUCTURES
    // ─────────────────────────────────────────────

    struct HostEarnings {
        address hostWallet;
        uint256 accruedAmount;       // Total unpaid earnings accumulated (in smallest currency unit)
        uint256 totalLifetimeEarned; // All-time total earned
        uint256 lastSettlementTime;  // When was the last payout made
        bool    payoutEnabled;       // Can this host receive payouts?
    }

    struct RenterAccount {
        address renterWallet;
        uint256 creditBalance;       // Prepaid credits remaining (in smallest currency unit)
        uint256 totalSpent;          // All-time total spent on storage
        uint256 lastBillingTime;     // When were they last billed
    }

    struct PaymentRecord {
        uint256 id;
        address recipient;           // Host wallet
        uint256 amount;              // Amount paid
        uint256 timestamp;           // When it was paid
        string  transactionRef;      // Razorpay/UPI transaction reference
        bool    settled;             // Was it actually paid out?
    }

    // ─────────────────────────────────────────────
    //  STATE VARIABLES
    // ─────────────────────────────────────────────

    address public owner;

    uint256 public settlementThreshold = 10000; // Minimum accrued amount before payout (in paise = ₹100)
    uint256 public platformFeePercent  = 5;      // Platform takes 5% of each payment
    uint256 public totalPaymentsCount;           // Total payment records

    mapping(address => HostEarnings)   public hostEarnings;     // host wallet → earnings
    mapping(address => RenterAccount)  public renterAccounts;   // renter wallet → credit account
    mapping(uint256  => PaymentRecord) public paymentRecords;   // payment ID → record

    address[] public registeredHosts;
    address[] public registeredRenters;

    // ─────────────────────────────────────────────
    //  EVENTS
    // ─────────────────────────────────────────────

    event CreditAdded(address indexed renter, uint256 amount);
    event StorageCharged(address indexed renter, address indexed host, uint256 amount, bytes32 fileId);
    event EarningsAccrued(address indexed host, uint256 amount, uint256 newTotal);
    event PaymentDue(address indexed host, uint256 amount, uint256 paymentId);
    event PaymentSettled(uint256 indexed paymentId, address indexed host, string transactionRef);
    event RenterLowBalance(address indexed renter, uint256 remainingBalance);

    // ─────────────────────────────────────────────
    //  MODIFIERS
    // ─────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "Only platform admin");
        _;
    }

    // ─────────────────────────────────────────────
    //  CONSTRUCTOR
    // ─────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
    }

    // ─────────────────────────────────────────────
    //  RENTER FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Register as a renter and add prepaid credits
    /// @dev In production, credits are purchased via Razorpay, then this is called
    ///      to record the credit on-chain. Amount is in smallest currency unit (paise).
    function addCredit(address _renter, uint256 _amount) external onlyOwner {
        if (renterAccounts[_renter].renterWallet == address(0)) {
            // First time — create account
            renterAccounts[_renter] = RenterAccount({
                renterWallet:    _renter,
                creditBalance:   0,
                totalSpent:      0,
                lastBillingTime: block.timestamp
            });
            registeredRenters.push(_renter);
        }
        renterAccounts[_renter].creditBalance += _amount;
        emit CreditAdded(_renter, _amount);
    }

    /// @notice Charge a renter for storage used and accrue earnings to the host
    /// @dev Called daily by the platform for each active file storage relationship
    /// @param _renter  The wallet address of the renter being charged
    /// @param _host    The wallet address of the host earning rent
    /// @param _amount  Amount to charge/earn (in smallest currency unit)
    /// @param _fileId  The file ID this charge relates to
    function chargeStorageUsage(
        address _renter,
        address _host,
        uint256 _amount,
        bytes32 _fileId
    ) external onlyOwner {
        RenterAccount storage renter = renterAccounts[_renter];
        require(renter.renterWallet != address(0), "Renter not registered");
        require(renter.creditBalance >= _amount, "Insufficient renter credit");

        // Deduct from renter's credit
        renter.creditBalance -= _amount;
        renter.totalSpent    += _amount;
        renter.lastBillingTime = block.timestamp;

        // Calculate platform fee
        uint256 platformFee    = (_amount * platformFeePercent) / 100;
        uint256 hostEarning    = _amount - platformFee;

        // Accrue earnings to host
        _accrueHostEarnings(_host, hostEarning);

        // Warn if renter balance is low (< ₹50 = 5000 paise)
        if (renter.creditBalance < 5000) {
            emit RenterLowBalance(_renter, renter.creditBalance);
        }

        emit StorageCharged(_renter, _host, _amount, _fileId);
    }

    // ─────────────────────────────────────────────
    //  HOST EARNINGS FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Register a host in the payment ledger
    function registerHost(address _hostWallet) external onlyOwner {
        require(hostEarnings[_hostWallet].hostWallet == address(0), "Host already registered");
        hostEarnings[_hostWallet] = HostEarnings({
            hostWallet:          _hostWallet,
            accruedAmount:       0,
            totalLifetimeEarned: 0,
            lastSettlementTime:  block.timestamp,
            payoutEnabled:       true
        });
        registeredHosts.push(_hostWallet);
    }

    /// @notice Internal function to add earnings to a host's ledger
    function _accrueHostEarnings(address _host, uint256 _amount) internal {
        HostEarnings storage earnings = hostEarnings[_host];
        if (earnings.hostWallet == address(0)) return;

        earnings.accruedAmount       += _amount;
        earnings.totalLifetimeEarned += _amount;

        emit EarningsAccrued(_host, _amount, earnings.accruedAmount);

        // If accrued amount exceeds settlement threshold → trigger payout
        if (earnings.accruedAmount >= settlementThreshold && earnings.payoutEnabled) {
            uint256 payoutAmount = earnings.accruedAmount;
            earnings.accruedAmount = 0;              // Reset after payout trigger
            earnings.lastSettlementTime = block.timestamp;

            // Create payment record
            uint256 paymentId = totalPaymentsCount++;
            paymentRecords[paymentId] = PaymentRecord({
                id:             paymentId,
                recipient:      _host,
                amount:         payoutAmount,
                timestamp:      block.timestamp,
                transactionRef: "",    // Will be filled after actual bank transfer
                settled:        false
            });

            // This event is listened to by the backend service which calls Razorpay
            emit PaymentDue(_host, payoutAmount, paymentId);
        }
    }

    /// @notice Record that a payment has been successfully sent via Razorpay/UPI
    /// @dev Called by backend service after confirming bank transfer
    /// @param _paymentId The payment record ID
    /// @param _transactionRef The Razorpay/UPI transaction reference number
    function confirmSettlement(uint256 _paymentId, string memory _transactionRef)
        external
        onlyOwner
    {
        PaymentRecord storage payment = paymentRecords[_paymentId];
        require(payment.recipient != address(0), "Payment record not found");
        require(!payment.settled, "Already settled");

        payment.settled        = true;
        payment.transactionRef = _transactionRef;

        emit PaymentSettled(_paymentId, payment.recipient, _transactionRef);
    }

    /// @notice Enable or disable payouts for a host (e.g., during disputes)
    function setPayoutEnabled(address _hostWallet, bool _enabled) external onlyOwner {
        hostEarnings[_hostWallet].payoutEnabled = _enabled;
    }

    // ─────────────────────────────────────────────
    //  VIEW FUNCTIONS
    // ─────────────────────────────────────────────

    /// @notice Get a host's current earnings balance
    function getHostEarnings(address _hostWallet)
        external
        view
        returns (HostEarnings memory)
    {
        return hostEarnings[_hostWallet];
    }

    /// @notice Get a renter's current credit balance
    function getRenterBalance(address _renterWallet)
        external
        view
        returns (uint256)
    {
        return renterAccounts[_renterWallet].creditBalance;
    }

    /// @notice Get a specific payment record
    function getPaymentRecord(uint256 _paymentId)
        external
        view
        returns (PaymentRecord memory)
    {
        return paymentRecords[_paymentId];
    }

    /// @notice Get all registered host addresses
    function getAllHosts() external view returns (address[] memory) {
        return registeredHosts;
    }
}

